"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[114829],{128560:e=>{e.exports=JSON.parse('{"tag":{"label":"repair","permalink":"/dst-api-webdocs/docs/tags/repair","allTagsPath":"/dst-api-webdocs/docs/tags","count":42,"items":[{"id":"game-scripts/prefabs/boards","title":"Boards","description":"A stackable inventory item used for repairing boats and as fuel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boards"},{"id":"game-scripts/components/boatleak","title":"Boatleak","description":"Manages visual, audio, and state transitions for boat leaks and repairs in DST, including plugged/unplugged states, repair timers, and integration with HullHealth for dynamic leak tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatleak"},{"id":"game-scripts/prefabs/boatpatch","title":"Boatpatch","description":"A game entity component that enables repairs to damaged boats using consumable patch materials (wood or kelp), providing health restoration and related functional behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatpatch"},{"id":"game-scripts/components/cookiecutterdrill","title":"CookieCutterDrill","description":"Manages the drilling progression for a cookie-cutter boat leak repair mechanism, handling animation state and damage application upon completion.","permalink":"/dst-api-webdocs/docs/game-scripts/components/cookiecutterdrill"},{"id":"game-scripts/prefabs/cutgrass","title":"Cutgrass","description":"A small, renewable grass item that serves as food, fuel, and repair material for entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cutgrass"},{"id":"game-scripts/prefabs/dock_damage","title":"Dock Damage","description":"Visual and logic entity that represents damaged segments of docks and rope bridges, synced to the world\'s dockmanager and ropebridgemanager for repair interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dock_damage"},{"id":"game-scripts/prefabs/dreadstone","title":"Dreadstone","description":"A consumable crafting material used for repairing tools and gear in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/dreadstone"},{"id":"game-scripts/prefabs/driftwood","title":"Driftwood","description":"A simple wood item that serves as fuel, edible material, repair resource, and waterproofer with zero effectiveness unless modified.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/driftwood"},{"id":"game-scripts/components/finiteuses","title":"Finiteuses","description":"Manages a finite number of uses for an entity\'s actions, updating repair status and tags as uses deplete.","permalink":"/dst-api-webdocs/docs/game-scripts/components/finiteuses"},{"id":"game-scripts/prefabs/forge_repair_kits","title":"Forge Repair Kits","description":"Creates consumable item prefabs that provide repair materials for the Forge component when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/forge_repair_kits"},{"id":"game-scripts/components/forgerepair","title":"Forgerepair","description":"Handles repair of damaged equipment using forge-based materials, consuming itself in the process and updating entity tags based on the repair material used.","permalink":"/dst-api-webdocs/docs/game-scripts/components/forgerepair"},{"id":"game-scripts/components/forgerepairable","title":"Forgerepairable","description":"Tracks and manages forge-repair eligibility of an entity based on repair material compatibility and current condition.","permalink":"/dst-api-webdocs/docs/game-scripts/components/forgerepairable"},{"id":"game-scripts/prefabs/fossil_mound","title":"Fossil Mound","description":"Serves as an interactive structure that spawns a Stalker when fully repaired and traded with a Shadow Heart under specific conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fossil_mound"},{"id":"game-scripts/prefabs/fossil_piece","title":"Fossil Piece","description":"A consumable inventory item that can be deployed to spawn a Fossil Stalker and repair structures using fossil material.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fossil_piece"},{"id":"game-scripts/prefabs/gears","title":"Gears","description":"A versatile consumable and repair item used for befriending clockwork creatures, restoring health/sanity/hunger, and repairing items in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gears"},{"id":"game-scripts/prefabs/inspectaclesbox","title":"Inspectaclesbox","description":"A loot-container entity that displays holographic projections and dispenses items based on the viewing player\'s recipe knowledge and repair status.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/inspectaclesbox"},{"id":"game-scripts/prefabs/inv_rocks","title":"Inv Rocks","description":"Represents a collectible stackable rock item usable as bait, repair material, and edible food in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/inv_rocks"},{"id":"game-scripts/prefabs/livinglog","title":"Livinglog","description":"A consumable and repair item that emits a sound effect when taken as fuel or ignited.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/livinglog"},{"id":"game-scripts/prefabs/mast_broken","title":"Mast Broken","description":"Represents a broken boat mast that can be repaired or burned, dropping loot and triggering visual/sound effects when interacted with.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mast_broken"},{"id":"game-scripts/prefabs/moon_fissure","title":"Moon Fissure","description":"Manages the visual and gameplay behavior of the Moon Fissure prop, which reacts to lunar phases and accepts moon altar pieces as repairs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moon_fissure"},{"id":"game-scripts/prefabs/moonbase","title":"Moonbase","description":"Manages the Moon Base structure\'s state, including staff charging, morphing, repair, and moon-based spawner activation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonbase"},{"id":"game-scripts/prefabs/moonrocknugget","title":"Moonrocknugget","description":"Prefab for a small, reusable crafting material that can be consumed for minimal nutrition, used in repairs, and dropped as loot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonrocknugget"},{"id":"game-scripts/prefabs/mosquitomusk","title":"Mosquitomusk","description":"A consumable inventory item that spoils over time and can be repaired with vitae material; used as bait for mosquito-based mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitomusk"},{"id":"game-scripts/prefabs/mosquitosack","title":"Mosquitosack","description":"A consumable inventory item that heals the user and repairs items while also acting as a combustible fuel source.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitosack"},{"id":"game-scripts/prefabs/nightmarefuel","title":"Nightmarefuel","description":"Implements a consumable item used as high-value fuel, repair material, and waterproofer in DST, with networked animation state and stacking support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmarefuel"},{"id":"game-scripts/prefabs/oceanice_damage","title":"Oceanice Damage","description":"A non-persistent visual and repairable entity that represents damage state of ocean ice and triggers ice restoration when repaired.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanice_damage"},{"id":"game-scripts/components/repairable","title":"Repairable","description":"Manages repair logic and tags for entities based on their state (health, durability, perishability, uses) and associated repair materials.","permalink":"/dst-api-webdocs/docs/game-scripts/components/repairable"},{"id":"game-scripts/components/repairer","title":"Repairer","description":"Adds repair capability to an entity by exposing material-specific repair properties and managing associated tags.","permalink":"/dst-api-webdocs/docs/game-scripts/components/repairer"},{"id":"game-scripts/prefabs/saltlick","title":"Saltlick","description":"A durable structure that provides salt-based sustenance for creatures and players over time, supporting improved construction and repair mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/saltlick"},{"id":"game-scripts/prefabs/saltrock","title":"Saltrock","description":"An elemental food item that serves as bait for moles, preserves other items, and repairs equipment using salt-based crafting material.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/saltrock"},{"id":"game-scripts/components/sewing","title":"Sewing","description":"Enables repair of entities with the \'needssewing\' tag using fuel-based or consumable sewing kits.","permalink":"/dst-api-webdocs/docs/game-scripts/components/sewing"},{"id":"game-scripts/prefabs/sewing_tape","title":"Sewing Tape","description":"A stackable inventory item used for repairing boats via the sewing system, providing a fixed amount of repair value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sewing_tape"},{"id":"game-scripts/prefabs/sewingkit","title":"Sewingkit","description":"Provides a consumable inventory item for repairing wearable equipment, using a finite number of uses and applying a fixed repair value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sewingkit"},{"id":"game-scripts/prefabs/slurtle_shellpieces","title":"Slurtle Shellpieces","description":"An inventory item that can be used to repair structures by providing shell-based repair material and a fixed health value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slurtle_shellpieces"},{"id":"game-scripts/prefabs/smashables","title":"Smashables","description":"Defines reusable prefabs for ruins-related smashable objects (e.g., relics, rubble, chairs) with repair, health, loot, and shadeling-spawning behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/smashables"},{"id":"game-scripts/prefabs/thulecite","title":"Thulecite","description":"A reusable crafting material that repairs tools and structures, and can be consumed for minimal sustenance.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/thulecite"},{"id":"game-scripts/prefabs/treegrowthsolution","title":"Treegrowthsolution","description":"Provides fertilizer functionality for repairing and regrowing trees in DST, including soil cycle progression and waterlogging compatibility.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/treegrowthsolution"},{"id":"game-scripts/prefabs/twigs","title":"Twigs","description":"A multi-functional small item that serves as fuel, food, repair material, and ocean fishing tackle in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/twigs"},{"id":"game-scripts/prefabs/wagdrone_parts","title":"Wagdrone Parts","description":"A repair item that restores wagdrones to full functionality and converts broken or unfriendly wagdrones into friendly ones.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagdrone_parts"},{"id":"game-scripts/prefabs/wagpunk_bits","title":"Wagpunk Bits","description":"A small stackable item used as bait for moles and for repairing gear-based structures and items in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagpunk_bits"},{"id":"game-scripts/brains/waveyjoneshandbrain","title":"Waveyjoneshandbrain","description":"Controls the behavior of Wavey Jones\' hand entity by selecting and performing repair-related actions on boat components based on current conditions and player sanity.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/waveyjoneshandbrain"},{"id":"game-scripts/components/workable","title":"Workable","description":"Manages the work state and completion logic for interactable entities in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/workable"}],"unlisted":false}}')}}]);